// ── Fuentes de datos ─────────────────────────────────────────────────────
const cfg           = $('Config Cliente').first().json;
const actual        = $('Sheet Actual').all().map(i => i.json);
const anterior      = $('Sheet Anterior').all().map(i => i.json);
const customTabRows = (() => { try { return $('Sheet Custom Tab').all().map(i => i.json).filter(r => !r._sin_evolutivo); } catch(e) { return []; } })();

const ga4ARaw = $('Dashbo GA4 Actual').first().json;
const ga4PRaw = $('Dashbo GA4 Anterior').first().json;
const ga4A    = Array.isArray(ga4ARaw.rows) ? ga4ARaw.rows[0] : ga4ARaw;
const ga4P    = Array.isArray(ga4PRaw.rows) ? ga4PRaw.rows[0] : ga4PRaw;

// ── Helpers ───────────────────────────────────────────────────────────────
const parseNum = str => {
  if (!str && str !== 0) return 0;
  const s = String(str).replace(/[$%\s]/g, '').replace(/\./g, '').replace(',', '.');
  return parseFloat(s) || 0;
};
const parseRate = str => {
  const s = String(str || '0').replace('%', '').trim();
  const n = parseFloat(s.replace(',', '.')) || 0;
  return (n > 0 && n < 1) ? n * 100 : n;
};
const fmtNum   = n => Math.round(n).toLocaleString('es-AR');
const fmtPct   = n => n.toFixed(1).replace('.', ',') + '%';
const fmtMoney = n => '$' + Math.round(n).toLocaleString('es-AR');
const getField = (row, ...keys) => {
  for (const k of keys) if (row[k] !== undefined && row[k] !== null && row[k] !== '') return row[k];
  return undefined;
};
const delta = (curr, prev, isRate = false) => {
  if (!prev || prev === 0) return { str: '—', up: true };
  if (isRate) {
    const d = curr - prev;
    return { str: (d >= 0 ? '+' : '') + d.toFixed(1).replace('.', ',') + 'pp', up: d >= 0 };
  }
  const pct = (curr - prev) / prev * 100;
  return { str: (pct >= 0 ? '+' : '') + pct.toFixed(0) + '%', up: pct >= 0 };
};

// ── Totales de un conjunto de filas ──────────────────────────────────────
const calcTotals = rows => {
  let envios = 0, trans = 0, ingresos = 0, sumAp = 0, sumCtor = 0, sumBajas = 0;
  rows.forEach(r => {
    const e = parseNum(getField(r, 'Delivered', 'Enviados', 'delivered'));
    envios   += e;
    trans    += parseNum(getField(r, 'Transacciones online', 'transacciones') || 0);
    ingresos += parseNum(getField(r, 'Ingresos online', 'ingresos') || 0);
    sumAp    += parseRate(getField(r, 'Open Rate', 'Tasa de apertura', 'open_rate')) * e;
    sumCtor  += parseRate(getField(r, 'CTOR', 'ctor')) * e;
    sumBajas += parseRate(getField(r, 'Unsubscribe Rate', 'Tasa de bajas', 'unsubscribe_rate')) * e;
  });
  return {
    envios, trans, ingresos,
    apertura: envios > 0 ? sumAp    / envios : 0,
    ctor:     envios > 0 ? sumCtor  / envios : 0,
    bajas:    envios > 0 ? sumBajas / envios : 0,
  };
};

// ── Totales generales (todos los tipos) ───────────────────────────────────
const a = calcTotals(actual);
const p = calcTotals(anterior);

const dEnvios   = delta(a.envios,   p.envios);
const dApertura = delta(a.apertura, p.apertura, true);
const dCtor     = delta(a.ctor,     p.ctor,     true);
const dBajas    = delta(a.bajas,    p.bajas,    true);
const dTrans    = delta(a.trans,    p.trans);
const dIngresos = delta(a.ingresos, p.ingresos);

// ── Detectar plataforma (desde primera fila del sheet) ───────────────────
const plataforma = String(getField(actual[0] || {}, 'Plataforma', 'plataforma', 'platform') || 'WOOWUP').toUpperCase();
const isWoowup   = plataforma === 'WOOWUP';

// ── Separar filas por Tipo (solo Woowup) ─────────────────────────────────
const getTipo = r => String(getField(r, 'Tipo', 'tipo', 'type') || '').trim().toLowerCase();
const actualNewsletter   = isWoowup ? actual.filter(r => getTipo(r) === 'newsletter')   : [];
const actualAutomatizada = isWoowup ? actual.filter(r => getTipo(r) === 'automatizada' || getTipo(r) === 'automtizada') : [];

// ── Construir array de campañas para un subconjunto de filas ─────────────
const hasTrans    = actual.some(r => parseNum(getField(r, 'Transacciones online', 'transacciones') || 0) > 0);
const hasIngresos = actual.some(r => parseNum(getField(r, 'Ingresos online', 'ingresos') || 0) > 0);

const buildCampanas = rows => rows
  .map(r => {
    const enviosRaw = parseNum(getField(r, 'Delivered', 'Enviados', 'delivered'));
    const obj = {
      nombre:   String(getField(r, 'Campaña', 'Campaign', 'campaña', 'campaign') || ''),
      envios:   fmtNum(enviosRaw),
      apertura: fmtPct(parseRate(getField(r, 'Open Rate', 'open_rate'))),
      ctor:     fmtPct(parseRate(getField(r, 'CTOR', 'ctor'))),
      bajas:    fmtPct(parseRate(getField(r, 'Unsubscribe Rate', 'unsubscribe_rate'))),
      _raw:     enviosRaw,
    };
    if (hasTrans)    obj.transacciones = fmtNum(parseNum(getField(r, 'Transacciones online', 'transacciones') || 0));
    if (hasIngresos) obj.ingresos      = fmtMoney(parseNum(getField(r, 'Ingresos online', 'ingresos') || 0));
    return obj;
  })
  .sort((x, y) => y._raw - x._raw)
  .map(({ _raw, ...rest }) => rest);

// ── GA4 Canal Email ───────────────────────────────────────────────────────
const ga4Ses   = parseNum(ga4A['GA4__Sesiones']                              || ga4A['Sesiones']           || 0);
const ga4SesP  = parseNum(ga4P['GA4__Sesiones']                              || ga4P['Sesiones']           || 0);
const ga4Ingr  = parseNum(ga4A['GA4__Ingresos_totales']                      || ga4A['Ingresos_totales']   || 0);
const ga4IngrP = parseNum(ga4P['GA4__Ingresos_totales']                      || ga4P['Ingresos_totales']   || 0);
const ga4Tr    = parseNum(ga4A['GA4__Transacciones_de_comercio_electrónico'] || ga4A['Transacciones']      || 0);
const ga4TrP   = parseNum(ga4P['GA4__Transacciones_de_comercio_electrónico'] || ga4P['Transacciones']      || 0);
const ga4Conv  = parseRate(ga4A['GA4__Tasa_de_conversión_de_sesiones']       || ga4A['Tasa_de_conversión'] || 0);
const ga4ConvP = parseRate(ga4P['GA4__Tasa_de_conversión_de_sesiones']       || ga4P['Tasa_de_conversión'] || 0);

const hasGA4 = ga4Ses > 0;
const dGA4Ses  = delta(ga4Ses,  ga4SesP);
const dGA4Ingr = delta(ga4Ingr, ga4IngrP);
const dGA4Tr   = delta(ga4Tr,   ga4TrP);
const dGA4Conv = delta(ga4Conv, ga4ConvP, true);

// ── DATA final ────────────────────────────────────────────────────────────
const DATA = {
  CLIENTE_NOMBRE:         cfg.CLIENTE_NOMBRE        || '',
  CLIENTE_LOGO_URL:       cfg.CLIENTE_LOGO_URL       || '',
  PERIODO_ACTUAL_LABEL:   cfg.PERIODO_ACTUAL_LABEL   || '',
  PERIODO_ANTERIOR_LABEL: cfg.PERIODO_ANTERIOR_LABEL || '',
  WEB:                    'www.knownonline.com',
  CONTACTO:               'ariel@knownonline.com',

  // KPIs generales (suma de newsletter + automatizadas)
  EMAIL_ENVIOS:          fmtNum(a.envios),
  EMAIL_ENVIOS_PREV:     fmtNum(p.envios),
  EMAIL_ENVIOS_DELTA:    dEnvios.str,
  EMAIL_ENVIOS_DELTA_UP: dEnvios.up,

  EMAIL_APERTURA:          fmtPct(a.apertura),
  EMAIL_APERTURA_PREV:     fmtPct(p.apertura),
  EMAIL_APERTURA_DELTA:    dApertura.str,
  EMAIL_APERTURA_DELTA_UP: dApertura.up,

  EMAIL_CTOR:          fmtPct(a.ctor),
  EMAIL_CTOR_PREV:     fmtPct(p.ctor),
  EMAIL_CTOR_DELTA:    dCtor.str,
  EMAIL_CTOR_DELTA_UP: dCtor.up,

  EMAIL_BAJAS:          fmtPct(a.bajas),
  EMAIL_BAJAS_PREV:     fmtPct(p.bajas),
  EMAIL_BAJAS_DELTA:    dBajas.str,
  EMAIL_BAJAS_DELTA_UP: dBajas.up,

  ...(a.trans > 0 ? {
    EMAIL_TRANSACCIONES:          fmtNum(a.trans),
    EMAIL_TRANSACCIONES_PREV:     fmtNum(p.trans),
    EMAIL_TRANSACCIONES_DELTA:    dTrans.str,
    EMAIL_TRANSACCIONES_DELTA_UP: dTrans.up,
  } : {}),

  ...(a.ingresos > 0 ? {
    EMAIL_INGRESOS:          fmtMoney(a.ingresos),
    EMAIL_INGRESOS_PREV:     fmtMoney(p.ingresos),
    EMAIL_INGRESOS_DELTA:    dIngresos.str,
    EMAIL_INGRESOS_DELTA_UP: dIngresos.up,
  } : {}),

  // Campañas: Woowup separa por tipo, otras plataformas usan EMAIL_CAMPANAS
  PLATAFORMA_EMAIL:            plataforma,
  ...(isWoowup ? {
    EMAIL_CAMPANAS_NEWSLETTER:   buildCampanas(actualNewsletter),
    EMAIL_CAMPANAS_AUTOMATIZADA: buildCampanas(actualAutomatizada),
  } : {
    EMAIL_CAMPANAS: buildCampanas(actual),
  }),

  GA4_TIENE_DATOS: hasGA4,
  ...(hasGA4 ? {
    GA4_SESIONES:               fmtNum(ga4Ses),
    GA4_SESIONES_PREV:          fmtNum(ga4SesP),
    GA4_SESIONES_DELTA:         dGA4Ses.str,
    GA4_SESIONES_DELTA_UP:      dGA4Ses.up,
    GA4_INGRESOS:               fmtMoney(ga4Ingr),
    GA4_INGRESOS_PREV:          fmtMoney(ga4IngrP),
    GA4_INGRESOS_DELTA:         dGA4Ingr.str,
    GA4_INGRESOS_DELTA_UP:      dGA4Ingr.up,
    GA4_TRANSACCIONES:          fmtNum(ga4Tr),
    GA4_TRANSACCIONES_PREV:     fmtNum(ga4TrP),
    GA4_TRANSACCIONES_DELTA:    dGA4Tr.str,
    GA4_TRANSACCIONES_DELTA_UP: dGA4Tr.up,
    GA4_TASA_CONV:              fmtPct(ga4Conv),
    GA4_TASA_CONV_PREV:         fmtPct(ga4ConvP),
    GA4_TASA_CONV_DELTA:        dGA4Conv.str,
    GA4_TASA_CONV_DELTA_UP:     dGA4Conv.up,
  } : {}),

  RECOMENDACIONES: [],

  // Evolutivo — solo si hay custom tab configurado
  ...(customTabRows.length > 0 ? { EVOLUTIVO_ROWS: customTabRows } : {}),
};

return [{ json: { DATA } }];
